import pytest
from source import process_transaction

def test_process_transaction_valid_input_does_not_return_none():
    """process_transaction should not silently return None for a valid transaction."""
    try:
        result = process_transaction('item1:100')
    except NameError:
        # Expected if the underlying implementation correctly propagates the missing function error
        return
    assert result is not None, "process_transaction returned None instead of a valid total or raising an error"
